import { TelemetryRow, HourlyData, ColumnMapping } from '../types';

declare global {
  interface Window {
    XLSX: any;
  }
}

// Helper to parse numbers that might use comma as decimal separator
const parseValue = (val: any): number => {
  if (typeof val === 'number') return val;
  if (typeof val === 'string') {
    // Remove whitespace and replace comma with dot
    const cleanStr = val.trim().replace(',', '.');
    // Remove characters that are not digits, dot, or minus
    const numberOnly = cleanStr.replace(/[^0-9.-]/g, '');
    const num = parseFloat(numberOnly);
    return isNaN(num) ? 0 : num;
  }
  return 0;
};

// Helper to parse Date/Time
const parseDateTime = (dateVal: any, timeVal: any): Date | null => {
    let finalDate: Date | null = null;

    // --- CASE 1: Separate Time Column Exists ---
    if (timeVal !== undefined && timeVal !== null && String(timeVal).trim() !== '') {

        // Sub-case 1.1: Excel Serial Numbers (Date Int + Time Decimal)
        // e.g. Date=45353, Time=0.5 (12:00) -> 45353.5
        if (typeof dateVal === 'number' && typeof timeVal === 'number') {
             const total = Math.floor(dateVal) + (timeVal % 1); // Ensure integer date + fraction time
             finalDate = new Date((total - 25569) * 86400 * 1000);
        }
        // Sub-case 1.2: Date is DateObject/Serial, Time is String (e.g. "14:30")
        else {
             // 1. Parse Date part
             let d = new Date();
             if (typeof dateVal === 'number') {
                 d = new Date((dateVal - 25569) * 86400 * 1000);
             } else if (dateVal instanceof Date) {
                 d = new Date(dateVal);
             } else {
                 // Try string parsing DD/MM/YYYY
                 const dStr = String(dateVal).trim();
                 // Matches DD/MM/YYYY or DD-MM-YYYY
                 const parts = dStr.split(/[\/\-\s]/);
                 if (parts.length >= 3) {
                     // Assume DD/MM/YYYY if 3 parts found
                     // Note: year might be first or last, simplistic heuristic here:
                     const p1 = parseInt(parts[0]);
                     const p2 = parseInt(parts[1]);
                     const p3 = parseInt(parts[2]);
                     if(p3 > 1000) d = new Date(p3, p2 - 1, p1); // DD/MM/YYYY
                     else if(p1 > 1000) d = new Date(p1, p2 - 1, p3); // YYYY/MM/DD
                 } else {
                     d = new Date(dStr);
                 }
             }

             // 2. Parse Time part
             let hours = 0;
             let minutes = 0;

             if (typeof timeVal === 'number') {
                 // Convert fraction of day to hours/min
                 // 0.5 = 12:00
                 const totalSeconds = Math.round(timeVal * 86400);
                 hours = Math.floor(totalSeconds / 3600);
                 minutes = Math.floor((totalSeconds % 3600) / 60);
             } else {
                 const tStr = String(timeVal).trim();
                 // Supports "14:30", "14:30:00"
                 const tParts = tStr.split(':');
                 if (tParts.length >= 2) {
                     hours = parseInt(tParts[0]);
                     minutes = parseInt(tParts[1]);
                 }
             }

             // 3. Combine
             if (!isNaN(d.getTime())) {
                 d.setHours(hours, minutes, 0, 0);
                 finalDate = d;
             }
        }
    } 
    // --- CASE 2: Single Column (Date and Time together) ---
    else {
        if (typeof dateVal === 'number') {
            finalDate = new Date((dateVal - 25569) * 86400 * 1000);
        } else if (typeof dateVal === 'string') {
             let d = new Date(dateVal);
             if (isNaN(d.getTime())) {
                const parts = dateVal.split(/[\/\-\s:]/);
                // Heuristic for DD/MM/YYYY HH:MM
                if (parts.length >= 5) {
                   d = new Date(
                     parseInt(parts[2]),
                     parseInt(parts[1]) - 1,
                     parseInt(parts[0]),
                     parseInt(parts[3]),
                     parseInt(parts[4])
                   );
                }
             }
             if (!isNaN(d.getTime())) finalDate = d;
        }
    }

    // Adjust for Timezone offset if needed or ensure validity
    if (finalDate && !isNaN(finalDate.getTime()) && finalDate.getFullYear() > 1990) {
        // Round to nearest minute to avoid floating point seconds issues from Excel serial conversion
        finalDate.setSeconds(0, 0);
        return finalDate;
    }
    return null;
};

// Get preview of the first file (raw matrix)
export const getExcelPreview = async (file: File): Promise<any[][]> => {
  const dataBuffer = await file.arrayBuffer();
  const workbook = window.XLSX.read(dataBuffer, { type: 'array' });
  const sheetName = workbook.SheetNames[0];
  const sheet = workbook.Sheets[sheetName];
  // header: 1 returns array of arrays
  return window.XLSX.utils.sheet_to_json(sheet, { header: 1 });
};

// Parse uploaded files based on user mapping
export const parseExcelFiles = async (files: File[], mapping: ColumnMapping): Promise<{ data: TelemetryRow[], cpe: string | null }> => {
  const allRows: TelemetryRow[] = [];
  let detectedCpe: string | null = null;

  // Calculate row offsets relative to the Date row
  const timeOffset = (mapping.timeRow !== undefined) ? (mapping.timeRow - mapping.dateRow) : 0;
  const activeOffset = mapping.activeRow - mapping.dateRow;
  const inductiveOffset = mapping.inductiveRow - mapping.dateRow;
  const capacitiveOffset = mapping.capacitiveRow - mapping.dateRow;

  for (let fIndex = 0; fIndex < files.length; fIndex++) {
    const file = files[fIndex];
    const dataBuffer = await file.arrayBuffer();
    const workbook = window.XLSX.read(dataBuffer, { type: 'array' });
    const sheetName = workbook.SheetNames[0];
    const sheet = workbook.Sheets[sheetName];
    const jsonData: any[][] = window.XLSX.utils.sheet_to_json(sheet, { header: 1 });

    // Extract CPE from the first file only
    if (fIndex === 0 && mapping.cpeRow !== undefined && mapping.cpeCol !== undefined) {
       const row = jsonData[mapping.cpeRow];
       if (row && row[mapping.cpeCol]) {
         detectedCpe = String(row[mapping.cpeCol]).trim();
       }
    }

    // Iterate data rows starting from the defined Date Start Row
    for (let i = mapping.dateRow; i < jsonData.length; i++) {
      const row = jsonData[i];
      if (!row || row.length === 0) continue;

      const dateVal = row[mapping.dateCol];

      // Get Time Value with offset
      let timeVal = undefined;
      if (mapping.timeCol !== undefined) {
         if (jsonData[i + timeOffset]) {
             timeVal = jsonData[i + timeOffset][mapping.timeCol];
         }
      }

      const date = parseDateTime(dateVal, timeVal);

      if (date) {
         let active = 0, inductive = 0, capacitive = 0;
         if (jsonData[i + activeOffset]) active = parseValue(jsonData[i + activeOffset][mapping.activeCol]);
         if (jsonData[i + inductiveOffset]) inductive = parseValue(jsonData[i + inductiveOffset][mapping.inductiveCol]);
         if (jsonData[i + capacitiveOffset]) capacitive = parseValue(jsonData[i + capacitiveOffset][mapping.capacitiveCol]);

         allRows.push({
           timestamp: date,
           activePower: active,
           inductivePower: inductive,
           capacitivePower: capacitive,
         });
      }
    }
  }

  const sortedData = allRows.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());

  return {
    data: sortedData,
    cpe: detectedCpe
  };
};

// Aggregation Logic: 15min -> 1 Hour
export const aggregateToHourly = (rows: TelemetryRow[]): HourlyData[] => {
  const grouped: Record<string, TelemetryRow[]> = {};

  rows.forEach(row => {
    const d = new Date(row.timestamp);
    d.setMinutes(0, 0, 0); 
    const key = d.toISOString();

    if (!grouped[key]) grouped[key] = [];
    grouped[key].push(row);
  });

  return Object.keys(grouped).map(key => {
    const group = grouped[key];
    const date = new Date(key);

    const actives = group.map(r => r.activePower);
    const activeAvg = actives.reduce((a, b) => a + b, 0) / group.length;

    const inductives = group.map(r => r.inductivePower);
    const inductiveAvg = inductives.reduce((a, b) => a + b, 0) / group.length;

    const capacitives = group.map(r => r.capacitivePower);
    const capAvg = capacitives.reduce((a, b) => a + b, 0) / group.length;

    return {
      timestamp: date,
      hourLabel: date.toLocaleString('pt-PT', { month: 'short', day: '2-digit', hour: '2-digit', minute: '2-digit' }),
      activeAvg,
      activeMax: Math.max(...actives),
      activeMin: Math.min(...actives),
      inductiveAvg,
      inductiveMax: Math.max(...inductives),
      inductiveMin: Math.min(...inductives),
      capacitiveAvg: capAvg,
      capacitiveMax: Math.max(...capacitives),
      capacitiveMin: Math.min(...capacitives),
    };
  }).sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
};

export interface ExportConfig {
    resolution: 'raw' | 'hourly' | 'daily' | 'monthly';
    splitDateTime: boolean;
    columns: {
        active: boolean;
        inductive: boolean;
        capacitive: boolean;
    };
}

export const generateCSV = (data: any[], config: ExportConfig) => {
    // 1. Filter and Aggregate based on resolution
    let processedData: any[] = [];

    if (config.resolution === 'raw') {
         processedData = data.map((d: TelemetryRow) => ({
            timestamp: d.timestamp,
            date: d.timestamp.toLocaleDateString('pt-PT'),
            time: d.timestamp.toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }),
            dateTime: d.timestamp.toLocaleString('pt-PT'),
            active: d.activePower,
            inductive: d.inductivePower,
            capacitive: d.capacitivePower
        }));
    } else if (config.resolution === 'hourly') {
        processedData = data.map((d: HourlyData) => ({
            timestamp: d.timestamp,
            date: d.timestamp.toLocaleDateString('pt-PT'),
            time: d.timestamp.toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }),
            dateTime: d.timestamp.toLocaleString('pt-PT'),
            active: d.activeAvg,
            inductive: d.inductiveAvg,
            capacitive: d.capacitiveAvg
        }));
    } else {
        // Aggregate for Daily or Monthly
        const grouped: Record<string, { timestamp: Date, count: number, actSum: number, indSum: number, capSum: number }> = {};

        data.forEach(d => {
            let key = '';
            let ts = new Date(d.timestamp);
            if (config.resolution === 'daily') {
                key = d.timestamp.toLocaleDateString('pt-PT');
                ts.setHours(0,0,0,0);
            } else {
                // Monthly
                key = d.timestamp.toLocaleString('pt-PT', { month: 'long', year: 'numeric' });
                ts.setDate(1); ts.setHours(0,0,0,0);
            }

            if (!grouped[key]) grouped[key] = { timestamp: ts, count: 0, actSum: 0, indSum: 0, capSum: 0 };
            grouped[key].count++;
            grouped[key].actSum += d.activeAvg;
            grouped[key].indSum += d.inductiveAvg;
            grouped[key].capSum += d.capacitiveAvg;
        });

        processedData = Object.keys(grouped).map(k => {
            const g = grouped[k];
            // If resolution is Daily/Monthly, users usually want Total Energy (Sum of hourly averages)
            return {
                timestamp: g.timestamp,
                date: k,
                time: '',
                dateTime: k,
                active: g.actSum,
                inductive: g.indSum,
                capacitive: g.capSum
            };
        });
    }

    // 2. Build Headers
    const headers: string[] = [];
    if (config.splitDateTime) {
        headers.push('Data');
        if (config.resolution === 'hourly' || config.resolution === 'raw') headers.push('Hora');
    } else {
        headers.push('Período');
    }

    if (config.columns.active) headers.push((config.resolution === 'hourly' || config.resolution === 'raw') ? 'Ativa (kW)' : 'Ativa (kWh)');
    if (config.columns.inductive) headers.push((config.resolution === 'hourly' || config.resolution === 'raw') ? 'Indutiva (kVAr)' : 'Indutiva (kVArh)');
    if (config.columns.capacitive) headers.push((config.resolution === 'hourly' || config.resolution === 'raw') ? 'Capacitiva (kVAr)' : 'Capacitiva (kVArh)');

    // 3. Build Rows
    const rows = processedData.map(d => {
        const row: string[] = [];

        if (config.splitDateTime) {
            row.push(d.date);
            if (config.resolution === 'hourly' || config.resolution === 'raw') row.push(d.time);
        } else {
            row.push(d.dateTime);
        }

        if (config.columns.active) row.push(d.active.toFixed(2).replace('.', ','));
        if (config.columns.inductive) row.push(d.inductive.toFixed(2).replace('.', ','));
        if (config.columns.capacitive) row.push(d.capacitive.toFixed(2).replace('.', ','));
        return row;
    });

    // 4. Create CSV Content (using semi-colon separator)
    const csvContent = "\uFEFF" + [headers.join(';'), ...rows.map(e => e.join(';'))].join('\n');

    // 5. Trigger Download
    const encodedUri = encodeURI("data:text/csv;charset=utf-8," + csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `k-dataelect_export_${config.resolution}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

import React, { useState, useMemo, useEffect } from 'react';
import { ResponsiveContainer, ComposedChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, Area, ReferenceLine, Brush } from 'recharts';
import { HourlyData, TelemetryRow, LoadType, Period } from '../types';
import { generateCSV, ExportConfig } from '../services/dataService';

interface DashboardProps {
  data: HourlyData[];
  rawData: TelemetryRow[];
}

const Dashboard: React.FC<DashboardProps> = ({ data, rawData }) => {
  const [period, setPeriod] = useState<Period>(Period.MONTHLY);
  const [loadType, setLoadType] = useState<LoadType>(LoadType.ACTIVE);
  const [focusDate, setFocusDate] = useState<Date>(new Date());

  // Export Modal State
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);
  const [exportConfig, setExportConfig] = useState<ExportConfig>({
      resolution: 'hourly',
      splitDateTime: false,
      columns: { active: true, inductive: true, capacitive: true }
  });
  const [exportRange, setExportRange] = useState<'current' | 'all'>('current');

  // Initialize focus date when data loads
  useEffect(() => {
    if (data.length > 0) {
        // Default to the first month of data
        setFocusDate(new Date(data[0].timestamp));
    }
  }, [data]);

  // Global Stats Calculation (Annual / All Data)
  const globalStats = useMemo(() => {
    if (data.length === 0) return null;

    const stats = {
        active: { max: 0, min: Infinity, avg: 0, sum: 0 },
        inductive: { max: 0, min: Infinity, avg: 0, sum: 0 },
        capacitive: { max: 0, min: Infinity, avg: 0, sum: 0 },
        count: data.length
    };

    data.forEach(d => {
        // Active
        stats.active.max = Math.max(stats.active.max, d.activeMax);
        stats.active.min = Math.min(stats.active.min, d.activeMin);
        stats.active.sum += d.activeAvg; // Sum of hourly avg power = Energy (kWh)

        // Inductive
        stats.inductive.max = Math.max(stats.inductive.max, d.inductiveMax);
        stats.inductive.min = Math.min(stats.inductive.min, d.inductiveMin);
        stats.inductive.sum += d.inductiveAvg;

        // Capacitive
        stats.capacitive.max = Math.max(stats.capacitive.max, d.capacitiveMax);
        stats.capacitive.min = Math.min(stats.capacitive.min, d.capacitiveMin);
        stats.capacitive.sum += d.capacitiveAvg;
    });

    stats.active.avg = stats.active.sum / stats.count;
    stats.inductive.avg = stats.inductive.sum / stats.count;
    stats.capacitive.avg = stats.capacitive.sum / stats.count;

    return stats;
  }, [data]);

  // Filtering Data based on Period and Focus Date
  const filteredData = useMemo(() => {
    if (data.length === 0) return [];

    let start: Date, end: Date;
    const year = focusDate.getFullYear();
    const month = focusDate.getMonth();
    const day = focusDate.getDate();

    switch (period) {
        case Period.DAILY:
            start = new Date(year, month, day, 0, 0, 0);
            end = new Date(year, month, day, 23, 59, 59);
            break;
        case Period.WEEKLY:
            // Get Monday of the week
            const dayOfWeek = focusDate.getDay(); // 0 (Sun) - 6 (Sat)
            const diff = focusDate.getDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1); // adjust when day is sunday
            start = new Date(focusDate);
            start.setDate(diff);
            start.setHours(0,0,0,0);

            end = new Date(start);
            end.setDate(start.getDate() + 6);
            end.setHours(23,59,59,999);
            break;
        case Period.MONTHLY:
            start = new Date(year, month, 1);
            end = new Date(year, month + 1, 0, 23, 59, 59);
            break;
        case Period.YEARLY:
            start = new Date(year, 0, 1);
            end = new Date(year, 11, 31, 23, 59, 59);
            break;
        default:
            return data;
    }

    // This is for display purposes in charts/tables (Hourly format)
    return data
        .filter(d => d.timestamp >= start && d.timestamp <= end)
        .map(d => ({
            timestamp: d.timestamp.getTime(), 
            label: d.hourLabel,
            val: loadType === LoadType.ACTIVE ? d.activeAvg : (loadType === LoadType.INDUCTIVE ? d.inductiveAvg : d.capacitiveAvg),
            max: loadType === LoadType.ACTIVE ? d.activeMax : (loadType === LoadType.INDUCTIVE ? d.inductiveMax : d.capacitiveMax),
            min: loadType === LoadType.ACTIVE ? d.activeMin : (loadType === LoadType.INDUCTIVE ? d.inductiveMin : d.capacitiveMin),
        }));
  }, [data, period, focusDate, loadType]);

  // Navigation Handlers
  const handleNavigate = (direction: 'prev' | 'next') => {
      const newDate = new Date(focusDate);
      const delta = direction === 'next' ? 1 : -1;

      switch (period) {
          case Period.DAILY:
              newDate.setDate(newDate.getDate() + delta);
              break;
          case Period.WEEKLY:
              newDate.setDate(newDate.getDate() + (delta * 7));
              break;
          case Period.MONTHLY:
              newDate.setMonth(newDate.getMonth() + delta);
              break;
          case Period.YEARLY:
              newDate.setFullYear(newDate.getFullYear() + delta);
              break;
      }
      setFocusDate(newDate);
  };

  const getColor = () => {
      switch(loadType) {
          case LoadType.ACTIVE: return "#2563eb"; // Blue
          case LoadType.INDUCTIVE: return "#dc2626"; // Red
          case LoadType.CAPACITIVE: return "#16a34a"; // Green
      }
  };

  const viewStats = useMemo(() => {
      if(filteredData.length === 0) return null;
      const vals = filteredData.map(d => d.val);
      const maxes = filteredData.map(d => d.max);
      const sum = vals.reduce((a,b) => a+b, 0);
      return {
          min: Math.min(...vals),
          max: Math.max(...maxes),
          avg: sum / vals.length,
          sum: sum
      };
  }, [filteredData]);

  const formatXAxis = (tickItem: number) => {
      const d = new Date(tickItem);
      if (period === Period.DAILY) return d.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});
      if (period === Period.WEEKLY) return d.toLocaleDateString([], {weekday: 'short', day: 'numeric'});
      if (period === Period.MONTHLY) return d.toLocaleDateString([], {day: '2-digit'});
      if (period === Period.YEARLY) return d.toLocaleDateString([], {month: 'short'});
      return "";
  };

  const getPeriodLabel = () => {
      if (period === Period.DAILY) return focusDate.toLocaleDateString('pt-PT', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
      if (period === Period.WEEKLY) return `Semana de ${focusDate.toLocaleDateString('pt-PT', { day: 'numeric', month: 'long' })}`;
      if (period === Period.MONTHLY) return focusDate.toLocaleDateString('pt-PT', { month: 'long', year: 'numeric' });
      if (period === Period.YEARLY) return `Ano ${focusDate.getFullYear()}`;
      return "";
  };

  // Export Logic Handler
  const handleExport = () => {
      // Determine which dataset to use
      let datasetToExport: any[] = data; 

      // If raw resolution is selected, use rawData instead of hourly aggregated data
      if (exportConfig.resolution === 'raw') {
          datasetToExport = rawData;
      }

      if (exportRange === 'current') {
          // Re-filter source data based on current period
          let start: Date, end: Date;
          const year = focusDate.getFullYear();
          const month = focusDate.getMonth();
          const day = focusDate.getDate();

          if(period === Period.DAILY) {
              start = new Date(year, month, day, 0, 0, 0);
              end = new Date(year, month, day, 23, 59, 59);
          } else if(period === Period.WEEKLY) {
              const dayOfWeek = focusDate.getDay();
              const diff = focusDate.getDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1);
              start = new Date(focusDate); start.setDate(diff); start.setHours(0,0,0,0);
              end = new Date(start); end.setDate(start.getDate() + 6); end.setHours(23,59,59,999);
          } else if(period === Period.MONTHLY) {
              start = new Date(year, month, 1);
              end = new Date(year, month + 1, 0, 23, 59, 59);
          } else {
              start = new Date(year, 0, 1);
              end = new Date(year, 11, 31, 23, 59, 59);
          }

          datasetToExport = datasetToExport.filter((d: any) => d.timestamp >= start && d.timestamp <= end);
      }

      generateCSV(datasetToExport, exportConfig);
      setIsExportModalOpen(false);
  };

  return (
    <div className="space-y-6">

      {/* General Summary Table */}
      {globalStats && (
        <div className="bg-white p-6 rounded-lg shadow border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-700 mb-4 flex items-center border-b pb-2">
                <svg className="w-5 h-5 mr-2 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
                Resumo Geral da Instalação (Total Importado)
             </h3>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                 {/* Active */}
                 <div className="bg-blue-50 p-4 rounded border border-blue-100">
                    <h4 className="font-bold text-blue-800 mb-2 border-b border-blue-200 pb-1">Potência Ativa</h4>
                    <div className="flex justify-between text-sm mb-1"><span>Total Energia:</span> <span className="font-mono font-bold text-lg">{globalStats.active.sum.toLocaleString('pt-PT', {maximumFractionDigits: 0})} kWh</span></div>
                    <div className="flex justify-between text-sm mb-1"><span>Média Potência:</span> <span className="font-mono font-bold">{globalStats.active.avg.toFixed(2)} kW</span></div>
                    <div className="flex justify-between text-sm mb-1"><span>Máximo Registado:</span> <span className="font-mono font-bold">{globalStats.active.max.toFixed(2)} kW</span></div>
                 </div>
                 {/* Inductive */}
                 <div className="bg-red-50 p-4 rounded border border-red-100">
                    <h4 className="font-bold text-red-800 mb-2 border-b border-red-200 pb-1">Reativa Indutiva</h4>
                    <div className="flex justify-between text-sm mb-1"><span>Total Energia:</span> <span className="font-mono font-bold text-lg">{globalStats.inductive.sum.toLocaleString('pt-PT', {maximumFractionDigits: 0})} kVArh</span></div>
                    <div className="flex justify-between text-sm mb-1"><span>Média Potência:</span> <span className="font-mono font-bold">{globalStats.inductive.avg.toFixed(2)} kVAr</span></div>
                    <div className="flex justify-between text-sm"><span>Máximo Registado:</span> <span className="font-mono font-bold">{globalStats.inductive.max.toFixed(2)} kVAr</span></div>
                 </div>
                 {/* Capacitive */}
                 <div className="bg-green-50 p-4 rounded border border-green-100">
                    <h4 className="font-bold text-green-800 mb-2 border-b border-green-200 pb-1">Reativa Capacitiva</h4>
                    <div className="flex justify-between text-sm mb-1"><span>Total Energia:</span> <span className="font-mono font-bold text-lg">{globalStats.capacitive.sum.toLocaleString('pt-PT', {maximumFractionDigits: 0})} kVArh</span></div>
                    <div className="flex justify-between text-sm mb-1"><span>Média Potência:</span> <span className="font-mono font-bold">{globalStats.capacitive.avg.toFixed(2)} kVAr</span></div>
                    <div className="flex justify-between text-sm"><span>Máximo Registado:</span> <span className="font-mono font-bold">{globalStats.capacitive.max.toFixed(2)} kVAr</span></div>
                 </div>
             </div>
        </div>
      )}

      {/* Controls & Navigation */}
      <div className="bg-white p-4 rounded-lg shadow flex flex-col md:flex-row justify-between items-center gap-4">

        {/* Load Type Selector */}
        <div className="flex space-x-1 bg-gray-100 p-1 rounded-lg">
            {Object.values(LoadType).map((t) => (
                <button
                    key={t}
                    onClick={() => setLoadType(t)}
                    className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${
                        loadType === t ? 'bg-white text-blue-700 shadow' : 'text-gray-500 hover:text-gray-800'
                    }`}
                >
                    {t === 'active' ? 'Ativa (kW)' : t === 'inductive' ? 'Indutiva (kVAr)' : 'Capacitiva (kVAr)'}
                </button>
            ))}
        </div>

        {/* Period Selector */}
        <div className="flex space-x-2">
            {Object.values(Period).map((p) => (
                <button
                    key={p}
                    onClick={() => setPeriod(p)}
                    className={`px-3 py-1 rounded text-sm font-medium ${
                        period === p ? 'bg-blue-100 text-blue-700 ring-1 ring-blue-700' : 'text-gray-500 hover:text-gray-800'
                    }`}
                >
                    {p}
                </button>
            ))}
        </div>

        {/* Date Navigation */}
        <div className="flex items-center space-x-2 bg-gray-50 p-1 rounded border border-gray-200">
             <button onClick={() => handleNavigate('prev')} className="p-1 hover:bg-gray-200 rounded text-gray-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
             </button>

             <div className="text-sm font-bold w-48 text-center text-gray-800 capitalize select-none">
                 {getPeriodLabel()}
             </div>

             <button onClick={() => handleNavigate('next')} className="p-1 hover:bg-gray-200 rounded text-gray-600">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
             </button>

             {period !== Period.YEARLY && (
                 <input 
                    type={period === Period.MONTHLY ? "month" : "date"}
                    className="text-xs bg-white border border-gray-300 rounded px-2 py-1 outline-none focus:ring-1 focus:ring-blue-500"
                    onChange={(e) => {
                        if(e.target.value) setFocusDate(new Date(e.target.value));
                    }}
                    value={period === Period.MONTHLY 
                        ? `${focusDate.getFullYear()}-${String(focusDate.getMonth()+1).padStart(2,'0')}`
                        : `${focusDate.getFullYear()}-${String(focusDate.getMonth()+1).padStart(2,'0')}-${String(focusDate.getDate()).padStart(2,'0')}`
                    }
                 />
             )}
        </div>
      </div>

      {/* Chart */}
      <div className="bg-white p-6 rounded-lg shadow border border-gray-100 h-[500px]">
        <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-gray-700 capitalize">
                Gráfico {period} - {loadType === 'active' ? 'Potência Ativa' : loadType === 'inductive' ? 'Reativa Indutiva' : 'Reativa Capacitiva'}
            </h3>
            {viewStats && (
                <div className="text-xs text-gray-500 font-mono">
                    Total: <span className="font-bold text-gray-800">{viewStats.sum.toFixed(0)}</span> | 
                    Max: <span className="font-bold text-gray-800">{viewStats.max.toFixed(2)}</span>
                </div>
            )}
        </div>

        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={filteredData} margin={{ top: 5, right: 30, left: 20, bottom: 50 }}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e7eb" />
            <XAxis 
                dataKey="timestamp" 
                type="number"
                domain={['dataMin', 'dataMax']}
                tickFormatter={formatXAxis}
                fontSize={12} 
                tickMargin={10} 
                stroke="#9ca3af"
                scale="time"
                minTickGap={30}
            />
            <YAxis fontSize={12} stroke="#9ca3af" label={{ value: loadType === 'active' ? 'kW' : 'kVAr', angle: -90, position: 'insideLeft' }} />
            <Tooltip 
                labelFormatter={(ts) => new Date(ts).toLocaleString('pt-PT')}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} 
                labelStyle={{ color: '#374151', fontWeight: 'bold' }}
                formatter={(value: number) => [value.toFixed(2), loadType === 'active' ? 'kW' : 'kVAr']}
            />
            <Legend verticalAlign="top"/>
            <Area 
                type="monotone" 
                dataKey="val" 
                fill={getColor()} 
                fillOpacity={0.1} 
                stroke={getColor()} 
                strokeWidth={period === Period.YEARLY ? 1 : 2}
                name="Potência (Média 1h)" 
                activeDot={{ r: 4 }}
                dot={false}
                isAnimationActive={false} 
            />
            <Brush dataKey="timestamp" height={30} stroke="#8884d8" tickFormatter={formatXAxis} />
          </ComposedChart>
        </ResponsiveContainer>
      </div>

      {/* Data Table with Export */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="px-6 py-4 border-b border-gray-200 flex justify-between items-center">
             <h3 className="text-lg font-semibold text-gray-700">Dados Horários ({filteredData.length} registos)</h3>
             <button 
                onClick={() => setIsExportModalOpen(true)}
                className="text-sm bg-blue-50 text-blue-700 px-3 py-2 rounded hover:bg-blue-100 flex items-center border border-blue-200"
             >
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Exportar Excel (CSV)
             </button>
        </div>
        <div className="overflow-x-auto max-h-80">
            <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50 sticky top-0">
                    <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data/Hora</th>
                        <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Valor ({loadType === 'active' ? 'kW' : 'kVAr'})</th>
                    </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                    {filteredData.slice(0, 1000).map((row, idx) => (
                        <tr key={idx} className="hover:bg-gray-50">
                            <td className="px-6 py-2 whitespace-nowrap text-sm text-gray-900">{row.label}</td>
                            <td className="px-6 py-2 whitespace-nowrap text-sm text-right font-medium text-gray-900">{row.val.toFixed(2)}</td>
                        </tr>
                    ))}
                    {filteredData.length > 1000 && (
                        <tr>
                            <td colSpan={2} className="px-6 py-4 text-center text-gray-500 text-sm italic">
                                ... e mais {filteredData.length - 1000} linhas (exporte para ver tudo)
                            </td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
      </div>

      {/* Export Modal */}
      {isExportModalOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
              <div className="bg-slate-800 rounded-lg shadow-xl max-w-md w-full border border-gray-700">
                  <div className="p-4 border-b border-gray-700 bg-slate-900 rounded-t-lg">
                      <h3 className="text-xl font-bold text-white">Exportar Dados (CSV)</h3>
                  </div>

                  <div className="p-6 space-y-4">
                    {/* Range */}
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-2">Período</label>
                        <select 
                            className="w-full bg-slate-700 border border-slate-600 text-white p-2 rounded text-sm"
                            value={exportRange}
                            onChange={(e) => setExportRange(e.target.value as any)}
                        >
                            <option value="current">Apenas Período Atual ({getPeriodLabel()})</option>
                            <option value="all">Ano Completo (Todos os dados)</option>
                        </select>
                    </div>

                    {/* Resolution */}
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-2">Formato (Resolução)</label>
                        <select 
                            className="w-full bg-slate-700 border border-slate-600 text-white p-2 rounded text-sm"
                            value={exportConfig.resolution}
                            onChange={(e) => setExportConfig({...exportConfig, resolution: e.target.value as any})}
                        >
                            <option value="raw">Detalhado (Original / 15 min)</option>
                            <option value="hourly">Horário (1h)</option>
                            <option value="daily">Diário (24h)</option>
                            <option value="monthly">Mensal</option>
                        </select>
                        <p className="text-xs text-gray-400 mt-1">
                            {exportConfig.resolution === 'hourly' 
                                ? 'Exporta linhas para cada hora (Média).' 
                                : exportConfig.resolution === 'raw' 
                                    ? 'Exporta dados originais (normalmente 15m).' 
                                    : 'Exporta a soma de energia (kWh/kVArh) por dia ou mês.'}
                        </p>
                    </div>

                    {/* Date/Time Format */}
                    <div className="flex items-center">
                        <input 
                            type="checkbox" 
                            checked={exportConfig.splitDateTime} 
                            onChange={e => setExportConfig({...exportConfig, splitDateTime: e.target.checked})} 
                            className="mr-2 rounded border-gray-600 bg-slate-700 text-blue-500 focus:ring-blue-500"
                        />
                        <label className="text-sm font-medium text-gray-300">Separar Data e Hora em colunas</label>
                    </div>

                    {/* Columns */}
                    <div>
                        <label className="block text-sm font-medium text-gray-300 mb-2">Variáveis</label>
                        <div className="space-y-2 text-gray-200">
                            <label className="flex items-center">
                                <input type="checkbox" checked={exportConfig.columns.active} onChange={e => setExportConfig(p => ({...p, columns: {...p.columns, active: e.target.checked}}))} className="mr-2 rounded border-gray-600 bg-slate-700" />
                                Potência Ativa
                            </label>
                            <label className="flex items-center">
                                <input type="checkbox" checked={exportConfig.columns.inductive} onChange={e => setExportConfig(p => ({...p, columns: {...p.columns, inductive: e.target.checked}}))} className="mr-2 rounded border-gray-600 bg-slate-700" />
                                Reativa Indutiva
                            </label>
                            <label className="flex items-center">
                                <input type="checkbox" checked={exportConfig.columns.capacitive} onChange={e => setExportConfig(p => ({...p, columns: {...p.columns, capacitive: e.target.checked}}))} className="mr-2 rounded border-gray-600 bg-slate-700" />
                                Reativa Capacitiva
                            </label>
                        </div>
                    </div>

                    {/* Summary */}
                    <div className="bg-slate-900 p-3 rounded text-sm text-gray-400 border border-slate-700">
                        <p><strong>Resumo:</strong> Exportar dados {exportConfig.resolution === 'hourly' ? 'Horários' : exportConfig.resolution === 'daily' ? 'Diários' : exportConfig.resolution === 'raw' ? 'Originais (15m)' : 'Mensais'}.</p>
                        <p>Separador: Ponto e vírgula (;).</p>
                    </div>
                  </div>

                  <div className="flex justify-end gap-3 p-4 border-t border-gray-700 bg-slate-900 rounded-b-lg">
                      <button onClick={() => setIsExportModalOpen(false)} className="px-4 py-2 text-gray-300 hover:bg-gray-800 rounded">Cancelar</button>
                      <button onClick={handleExport} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 font-medium shadow-lg shadow-blue-900/50">Confirmar Exportação</button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Dashboard;

import React, { useState, useRef } from 'react';
import { InstallationMetadata, ProjectState, ViewMode, ColumnMapping } from './types';
import Dashboard from './components/Dashboard';
import ReportView from './components/ReportView';
import { aggregateToHourly, parseExcelFiles, getExcelPreview } from './services/dataService';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.UPLOAD);
  const [project, setProject] = useState<ProjectState>({
    metadata: {
        name: '',
        location: '',
        technician: '',
        reportDate: new Date().toISOString().split('T')[0],
        cpe: '',
        sourceInterval: '15m',
        filesCount: 0,
        totalRecords: 0
    },
    rawData: [],
    hourlyData: [],
    aiAnalysis: null
  });

  // Import Wizard State
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [previewData, setPreviewData] = useState<any[][]>([]);
  const [loading, setLoading] = useState(false);

  // Mapping now includes Rows
  const [mapping, setMapping] = useState<ColumnMapping>({
      dateCol: 0, dateRow: 1,
      timeCol: undefined, timeRow: undefined,
      activeCol: 1, activeRow: 1,
      inductiveCol: 2, inductiveRow: 1,
      capacitiveCol: 3, capacitiveRow: 1,
      cpeRow: undefined, cpeCol: undefined
  });

  // Variable selection checkboxes
  const [enabledVars, setEnabledVars] = useState({
      active: true,
      inductive: true,
      capacitive: true
  });

  type SelectionType = 'date' | 'time' | 'active' | 'inductive' | 'capacitive' | 'cpe' | 'none';
  const [selectionMode, setSelectionMode] = useState<SelectionType>('none');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const jsonInputRef = useRef<HTMLInputElement>(null);

  const resetProject = () => {
      if(window.confirm("Tem a certeza que deseja limpar todos os dados e começar um novo projeto?")) {
          setProject({
              metadata: { name: '', location: '', technician: '', reportDate: new Date().toISOString().split('T')[0], cpe: '', sourceInterval: '15m', filesCount: 0, totalRecords: 0 },
              rawData: [], hourlyData: [], aiAnalysis: null
          });
          setSelectedFiles([]);
          setPreviewData([]);
          setViewMode(ViewMode.UPLOAD);
      }
  };

  const handleMetadataChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      setProject(prev => ({
          ...prev,
          metadata: { ...prev.metadata, [e.target.name]: e.target.value }
      }));
  };

  const handleInitialFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
          const files = Array.from(e.target.files) as File[];
          setSelectedFiles(files);
          setLoading(true);
          try {
              // Read first file for preview
              const preview = await getExcelPreview(files[0]);
              setPreviewData(preview.slice(0, 30)); // Take first 30 rows

              // Reset mapping to reasonable defaults or empty
              setMapping({
                  dateCol: 0, dateRow: 0,
                  timeCol: undefined, timeRow: undefined,
                  activeCol: 1, activeRow: 0,
                  inductiveCol: 2, inductiveRow: 0,
                  capacitiveCol: 3, capacitiveRow: 0,
              });

              setViewMode(ViewMode.CONFIG_IMPORT);
          } catch (err) {
              alert("Erro ao ler ficheiro de pré-visualização.");
              console.error(err);
          } finally {
              setLoading(false);
          }
      }
  };

  const handleProcessFiles = async () => {
      setLoading(true);
      try {
          const { data: rawData, cpe } = await parseExcelFiles(selectedFiles, mapping);

          if (rawData.length === 0) {
            alert("Não foram encontrados dados válidos. Verifique as colunas selecionadas.");
            setLoading(false);
            return;
          }

          const hourlyData = aggregateToHourly(rawData);

          setProject(prev => ({
              ...prev,
              metadata: {
                ...prev.metadata,
                cpe: cpe || prev.metadata.cpe,
                filesCount: selectedFiles.length,
                totalRecords: rawData.length
              },
              rawData,
              hourlyData
          }));
          setViewMode(ViewMode.DASHBOARD);
      } catch (err) {
          alert("Erro ao processar ficheiros. Verifique se as colunas de Data e Hora estão corretas.");
          console.error(err);
      } finally {
          setLoading(false);
      }
  };

  // Main interaction handler for the grid
  const handleCellClick = (rowIndex: number, colIndex: number, val: any) => {
      if (selectionMode === 'none') return;

      if (selectionMode === 'cpe') {
          setMapping(prev => ({ ...prev, cpeRow: rowIndex, cpeCol: colIndex }));
          setProject(prev => ({ ...prev, metadata: { ...prev.metadata, cpe: String(val) }}));
      }
      else if (selectionMode === 'date') {
          setMapping(prev => ({ ...prev, dateRow: rowIndex, dateCol: colIndex }));
      }
      else if (selectionMode === 'time') {
          setMapping(prev => ({ ...prev, timeRow: rowIndex, timeCol: colIndex }));
      }
      else if (selectionMode === 'active' && enabledVars.active) {
          setMapping(prev => ({ ...prev, activeRow: rowIndex, activeCol: colIndex }));
      }
      else if (selectionMode === 'inductive' && enabledVars.inductive) {
          setMapping(prev => ({ ...prev, inductiveRow: rowIndex, inductiveCol: colIndex }));
      }
      else if (selectionMode === 'capacitive' && enabledVars.capacitive) {
          setMapping(prev => ({ ...prev, capacitiveRow: rowIndex, capacitiveCol: colIndex }));
      }
  };

  const saveProject = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(project));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", `k-dataelect_${project.metadata.name || 'projeto'}.json`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  const loadProject = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const obj = JSON.parse(event.target?.result as string);
              obj.rawData.forEach((r: any) => r.timestamp = new Date(r.timestamp));
              obj.hourlyData.forEach((r: any) => r.timestamp = new Date(r.timestamp));
              setProject(obj);
              setViewMode(ViewMode.DASHBOARD);
          } catch (err) {
              alert("Ficheiro de projeto inválido");
          }
      };
      reader.readAsText(file);
  };

  // Helper to get cell background based on mapping
  const getCellClass = (r: number, c: number) => {
      if (mapping.dateRow === r && mapping.dateCol === c) return "bg-gray-500 text-white ring-2 ring-gray-700";
      if (mapping.timeRow === r && mapping.timeCol === c) return "bg-orange-500 text-white ring-2 ring-orange-700";
      if (mapping.activeRow === r && mapping.activeCol === c) return "bg-blue-600 text-white ring-2 ring-blue-800";
      if (mapping.inductiveRow === r && mapping.inductiveCol === c) return "bg-red-600 text-white ring-2 ring-red-800";
      if (mapping.capacitiveRow === r && mapping.capacitiveCol === c) return "bg-green-600 text-white ring-2 ring-green-800";
      if (mapping.cpeRow === r && mapping.cpeCol === c) return "bg-purple-600 text-white ring-2 ring-purple-800";
      return "hover:bg-blue-50 cursor-pointer";
  };

  // Render Report View
  if (viewMode === ViewMode.REPORT) {
      return (
          <div className="bg-gray-500 min-h-screen p-8 print:p-0 print:bg-white">
               <div className="max-w-4xl mx-auto mb-4 no-print">
                   <button onClick={() => setViewMode(ViewMode.DASHBOARD)} className="text-white hover:text-gray-200 flex items-center">
                       &larr; Voltar ao Dashboard
                   </button>
               </div>
               <ReportView 
                  project={project} 
                  updateAnalysis={(text) => setProject(prev => ({ ...prev, aiAnalysis: text }))}
               />
          </div>
      );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-slate-800 font-sans">

      {/* Header */}
      <header className="bg-slate-900 text-white shadow-lg sticky top-0 z-40">
        <div className="container mx-auto px-4 py-3 flex justify-between items-center">
            <div>
                <h1 className="text-xl font-bold tracking-wider">K-DATAELECT</h1>
                <p className="text-[10px] text-gray-400">By Koelho2000 | v1.3</p>
            </div>
            <div className="flex gap-4 text-sm items-center">
                <button onClick={resetProject} className="bg-red-600 hover:bg-red-700 px-3 py-1 rounded transition text-xs font-bold uppercase tracking-wide">Novo Projeto</button>
                <div className="h-6 w-px bg-slate-700 mx-2"></div>
                <button onClick={saveProject} className="hover:text-blue-300 transition">Gravar</button>
                <button onClick={() => jsonInputRef.current?.click()} className="hover:text-blue-300 transition">Abrir</button>
                <input type="file" ref={jsonInputRef} onChange={loadProject} accept=".json" className="hidden" />
                <a href="https://www.koelho2000.com" target="_blank" rel="noreferrer" className="text-gray-400 hover:text-white">www.koelho2000.com</a>
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 py-8">

        {/* Metadata Inputs */}
        <div className="bg-slate-900 rounded-lg shadow-lg p-6 mb-8 border border-slate-700">
            <h2 className="text-lg font-semibold mb-4 text-white flex items-center">
                <svg className="w-5 h-5 mr-2 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
                Dados da Instalação
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-6 gap-4">
                <div className="md:col-span-1">
                    <label className="block text-xs text-gray-400 mb-1">CPE</label>
                    <input name="cpe" placeholder="PT000..." value={project.metadata.cpe} onChange={handleMetadataChange} className="w-full bg-slate-800 border border-slate-600 text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-500" />
                </div>
                <div className="md:col-span-1">
                    <label className="block text-xs text-gray-400 mb-1">Nome</label>
                    <input name="name" placeholder="Nome da Instalação" value={project.metadata.name} onChange={handleMetadataChange} className="w-full bg-slate-800 border border-slate-600 text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-500" />
                </div>
                <div className="md:col-span-1">
                    <label className="block text-xs text-gray-400 mb-1">Localização</label>
                    <input name="location" placeholder="Localização" value={project.metadata.location} onChange={handleMetadataChange} className="w-full bg-slate-800 border border-slate-600 text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-500" />
                </div>
                <div className="md:col-span-1">
                    <label className="block text-xs text-gray-400 mb-1">Técnico</label>
                    <input name="technician" placeholder="Técnico Responsável" value={project.metadata.technician} onChange={handleMetadataChange} className="w-full bg-slate-800 border border-slate-600 text-white p-2 rounded focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-500" />
